customCSS:
/* Nord Theme - Arctic Elegance */
@import url('https://fonts.googleapis.com/css2?family=Source+Sans+Pro:wght@300;400;600;700&family=Source+Code+Pro&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 10%, rgba(136, 192, 208, 0.18), transparent),
    radial-gradient(ellipse 500px 350px at 70% 90%, rgba(94, 129, 172, 0.12), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(136, 192, 208, 0.15);
  background: rgba(67, 76, 94, 0.9);
}

.stat-card::before {
  background: linear-gradient(90deg, #8fbcbb, #88c0d0, #81a1c1, #5e81ac);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(136, 192, 208, 0.3);
  box-shadow: 0 4px 20px rgba(136, 192, 208, 0.1);
}

.stat-value {
  text-shadow: none;
}

.celebration-title {
  color: #88c0d0 !important;
  text-shadow: 0 0 30px rgba(136, 192, 208, 0.4);
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(67, 76, 94, 0.7);
  border: 1px solid rgba(136, 192, 208, 0.1);
}

.miner-card:hover {
  border-color: rgba(163, 190, 140, 0.2);
}
